package sessioncache

import (
	"context"
	"errors"
	"fmt"
	"math/rand"
	"sync"
	"time"

	"github.com/sony/gobreaker/v2"
	"github.com/go-redis/redis/v9"
)

// ===== CONSTANTS (TUNED AGAINST INCIDENT DATA) =====

// From incident logs: peak connected clients across *all shards* = 1,501 at 23:30
// paygate-api uses all 3 shards (via redis cluster), but we'll assume 1 client per shard.
// At 23:14:12, paygate had `retry 1/2` and `circuit-breaker=DISABLED`.
