// Why not 128 like Python? Go connections are lighter-weight, and paygate uses Redis *cluster* (sharding by key),
// so it connects to multiple nodes — but per-node, we still need headroom.
// Observed peak: `redis_connected_clients` = 1,501; assuming 25% share for paygate → 375 clients.
// At 23:20, shard 2 replica (redis-sessions-2-1) had `used_memory_human:3.12G` — so it handled *all* paygate traffic.
// We'll use 128 max connections per shard (same as Python) to avoid connection slot exhaustion.
// Rationale: at 23:14:02, `pool exhausted` in sessionary; paygate likely contributed to the same pool exhaustion.

const (
	RedisPoolSizePerShard = 128 // Must match Python's REDIS_POOL_SIZE_PER_SHARD — see "DEPLOYMENT COORDINATION" below
	RedisSocketTimeout    = 750 * time.Millisecond
	RedisConnectTimeout   = 500 * time.Millisecond
)

// Circuit breaker thresholds — MUST match sessionary's thresholds (see "DEPLOYMENT COORDINATION")
const (
	CircuitBreakerFailureThreshold = 0.80  // 80% pool saturation → open circuit (same as Python)
	CircuitBreakerRecoveryTimeout  = 30 * time.Second
)

// Retry budget — MUST match sessionary's retry budget (same rate, same tokens)
const (
	RetryBudgetTokens      = 10  // tokens/sec (same as Python)
	RetryBudgetRefillRate  = 10  // tokens/sec (same as Python)
)

// Idempotency key prefix — shared with sessionary to avoid collisions
const (
	ShadowKeyPrefix = "sess:shadow:" // Must match Python's `sess:shadow:*`
	LiveKeyPrefix   = "sess:live:"   // Must match Python's `sess:live:*`
)

// Redis key TTL — MUST match sessionary's REDIS_TTL_SECONDS (3600s)
const SessionTTL = 3600 * time.Second

// Command timeout budget — MUST be shorter than upstream handler timeout
// paygate-api checkout handler timeout = 10s (standard for payment flow)
// We reserve 2.5s for Redis (headroom for RDB load), leaving 7.5s for checkout logic
const RedisCommandTimeout = 2500 * time.Millisecond

// ===== ERRORS =====

var (
	ErrIdempotencyConflict = errors.New("idempotency key already exists (duplicate request)")
	ErrCircuitOpen         = errors.New("circuit breaker is open")
	ErrRetryBudgetExhausted = errors.New("retry budget exhausted")
)

// ===== CIRCUIT BREAKER STATE TRACKING (gobreaker is fine, but we add pool-aware logic) =====

// PoolAwareCircuit wraps sony/gobreaker with Redis connection pool saturation tracking
type PoolAwareCircuit struct {
	breaker *gobreaker.Breaker
	pool    *redis.Pool
	maxConn int
	mu      sync.Mutex
}

func NewPoolAwareCircuit(maxConn int) *PoolAwareCircuit {
	c := &PoolAwareCircuit{
		maxConn: maxConn,
	}

	// Configure gobreaker: fail on saturation > 80%
	c.breaker = gobreaker.NewBreaker(gobreaker.Settings{
		Name: "redis_session_cache",
		ReadyToTrip: func(counts gobreaker.Counts) bool {
			// We override TripFunc to check pool saturation *at the time of failure*
			return false // we'll check manually in recordFailure()
		},
		IsSuccessful: func(err error) bool {
			return err == nil
		},
	})

	return c
}

func (c *PoolAwareCircuit) recordFailure() bool {
	c.mu.Lock()
	defer c.mu.Unlock()

	// Get pool stats without blocking
	stats := c.pool.Stats()
	inUse := stats.Active
	saturation := float64(inUse) / float64(c.maxConn)

	if saturation > CircuitBreakerFailureThreshold {
		// Open circuit *now* on saturation, not after N failures
		c.breaker.Fire(gobreaker.EventTrip)
		return true
	}
	return false
}

func (c *PoolAwareCircuit) recordSuccess() {
	c.mu.Lock()
	defer c.mu.Unlock()
	c.breaker.Fire(gobreaker.EventSuccess)
}

func (c *PoolAwareCircuit) IsAvailable() bool {
	return c.breaker.Ready()
}

func (c *PoolAwareCircuit) Execute(ctx context.Context, fn func() error) error {
	return c.breaker.Execute(func() error {
		return fn()
	})
}

// ===== TOKEN BUCKET FOR RETRY BUDGET =====

type RetryBudget struct {
	tokens     float64
	lastRefill time.Time
	mu         sync.Mutex
}

func NewRetryBudget() *RetryBudget {
	return &RetryBudget{
		tokens:     RetryBudgetTokens,
		lastRefill: time.Now(),
	}
}

func (b *RetryBudget) Consume() bool {
	b.mu.Lock()
	defer b.mu.Unlock()

	now := time.Now()
	elapsed := now.Sub(b.lastRefill).Seconds()
	b.tokens = min(RetryBudgetTokens, b.tokens+elapsed*RetryBudgetRefillRate)
	b.lastRefill = now

	if b.tokens >= 1.0 {
		b.tokens -= 1.0
		return true
	}
	return false
}

// ===== CLIENT STRUCT =====

// Client is the Redis session cache client for paygate
type Client struct {
	redisClients []*redis.Client // one per shard (shard 0, 1, 2)
	circuit      *PoolAwareCircuit
	retryBudget  *RetryBudget
}

// NewClient constructs a new session cache client
func NewClient(shardHosts []string) (*Client, error) {
	if len(shardHosts) == 0 {
		return nil, errors.New("no Redis hosts provided")
	}

	clients := make([]*redis.Client, 0, len(shardHosts))
	for _, host := range shardHosts {
		client := redis.NewClient(&redis.Options{
			Addr:         host + ":6379",
			Password:     "", // no auth in prod
			DB:           0,
			MaxConnAge:   10 * time.Minute, // prevent stale connections
			PoolSize:     RedisPoolSizePerShard, // must match Python's REDIS_POOL_SIZE_PER_SHARD
			MinIdleConns: 10,
			MaxIdleConns: 128,
			ConnMaxIdleTime: 5 * time.Minute,
			// Critical: short timeouts to avoid cascading hangs
			MaxRetries:      0, // we implement our own retry with budget
			MinRetryBackoff: 50 * time.Millisecond,
			MaxRetryBackoff: 200 * time.Millisecond,
			DialTimeout:     RedisConnectTimeout,
			ReadTimeout:     RedisSocketTimeout,
			WriteTimeout:    RedisSocketTimeout,
			PoolTimeout:     RedisConnectTimeout,
		})

		// Verify connection
		if err := client.Ping(context.Background()).Err(); err != nil {
			return nil, fmt.Errorf("failed to ping Redis at %s: %w", host, err)
		}
		clients = append(clients, client)
	}

	// Use shard 0's connection pool for circuit breaker tracking
	circuit := NewPoolAwareCircuit(RedisPoolSizePerShard)
	circuit.pool = clients[0].Pool()

	return &Client{
		redisClients: clients,
		circuit:      circuit,
		retryBudget:  NewRetryBudget(),
	}, nil
}

// ShardForKey returns the shard index for a given key using the same hash as Python's redis-py (CRC16)
func ShardForKey(key string) int {
	// Redis cluster uses CRC16(key) mod 16384, but paygate uses 3 shards → mod 3
	// We'll use the same hash function as Python's redis-py (redis.client.parse_response uses crc16)
	// For simplicity, we'll use redis's built-in hash function (CRC16) via cluster client, but here we simulate:
	// In production, use github.com/redis/go-redis/cluster's HashKey(key) or redis-py-compatible hash
	// Here we assume key hashing matches sessionary: same key → same shard
	return int(crc16(key) % 3)
}

// crc16 is a simple CRC16 implementation for key hashing (matches Redis cluster)
// Source: https://github.com/redis/go-redis/blob/master/internal/hash.go#L10
func crc16(key string) uint16 {
	var crc uint16 = 0xFFFF
	for i := 0; i < len(key); i++ {
		crc ^= uint16(key[i]) << 8
		for j := 0; j < 8; j++ {
			if (crc & 0x8000) != 0 {
				crc = (crc << 1) ^ 0x1021
			} else {
				crc <<= 1
			}
		}
	}
	return crc
}

// Reserve attempts to reserve an idempotency key (SETNX pattern)
// Returns (success, err) — err may be context.DeadlineExceeded, Redis error, or idempotency conflict
func (c *Client) Reserve(ctx context.Context, key string, value string) (bool, error) {
	// Pre-check: circuit must be available
	if !c.circuit.IsAvailable() {
		return false, ErrCircuitOpen
	}

	// Compute shard — must match sessionary's key hashing
	shard := ShardForKey(key)

	// Short-circuit if key is shadow key — fail fast
	if len(key) >= len(ShadowKeyPrefix) && key[:len(ShadowKeyPrefix)] == ShadowKeyPrefix {
		return false, fmt.Errorf("shadow keyspace is write-protected: %s", key)
	}

	// Command timeout budget — must be shorter than upstream handler
	cmdCtx, cancel := context.WithTimeout(ctx, RedisCommandTimeout)
	defer cancel()

	// Identify the idempotency key prefix
	idemPrefix := LiveKeyPrefix
	if len(key) >= len(LiveKeyPrefix) && key[:len(LiveKeyPrefix)] == LiveKeyPrefix {
		// Already a live key — do not retry blindly
		idemPrefix = LiveKeyPrefix
	} else {
		// Ensure key is under live keyspace — fail if not
		return false, fmt.Errorf("key %s must start with %s", key, LiveKeyPrefix)
	}

	// Get Redis client for shard
	client := c.redisClients[shard]

	// First attempt: execute SETNX with TTL
	cmd := client.SetNX(cmdCtx, key, value, SessionTTL)

	// Check if command was *sent* to Redis before deadline exceeded
	// go-redis sets cmd.Err() on network failure, cmd.Val() on success/failure
	if cmd.Err() != nil {
		// Command failed before reaching Redis (network issue) — safe to retry
		return c.retryReserve(ctx, client, key, value, cmd.Err())
	}

	// Command was sent — check if SETNX succeeded
	if cmd.Val() {
		// Success: key was set
		c.circuit.recordSuccess()
		return true, nil
	}

	// Key already exists → idempotency conflict
	return false, ErrIdempotencyConflict
}

// retryReserve handles idempotency-aware retries
func (c *Client) retryReserve(ctx context.Context, client *redis.Client, key, value string, initialErr error) (bool, error) {
	// Only retry if context still has time and retry budget allows
	if !c.retryBudget.Consume() {
		return false, ErrRetryBudgetExhausted
	}

	// Re-check circuit — may have opened during first attempt
	if !c.circuit.IsAvailable() {
		return false, ErrCircuitOpen
	}

	// Re-create context with remaining timeout (if any)
	cmdCtx, cancel := context.WithTimeout(ctx, RedisCommandTimeout)
	defer cancel()

	// Retry SETNX
	cmd := client.SetNX(cmdCtx, key, value, SessionTTL)

	if cmd.Err() != nil {
		// Still failed — record failure for circuit breaker
		c.circuit.recordFailure()
		return false, cmd.Err()
	}

	if cmd.Val() {
		c.circuit.recordSuccess()
		return true, nil
	}

	return false, ErrIdempotencyConflict
}

// Get retrieves a session from Redis
func (c *Client) Get(ctx context.Context, key string) (string, error) {
	if !c.circuit.IsAvailable() {
		return "", ErrCircuitOpen
	}

	shard := ShardForKey(key)
	if shard >= len(c.redisClients) {
		return "", fmt.Errorf("invalid shard index: %d", shard)
	}

	client := c.redisClients[shard]
	cmdCtx, cancel := context.WithTimeout(ctx, RedisCommandTimeout)
	defer cancel()

	cmd := client.Get(cmdCtx, key)
	if cmd.Err() != nil {
		c.circuit.recordFailure()
		return "", cmd.Err()
	}
	c.circuit.recordSuccess()
	return cmd.Val(), nil
}

// Put writes a session with TTL enforcement — no TTL args accepted
func (c *Client) Put(ctx context.Context, key, value string) error {
	if !c.circuit.IsAvailable() {
		return ErrCircuitOpen
	}

	shard := ShardForKey(key)
	client := c.redisClients[shard]

	cmdCtx, cancel := context.WithTimeout(ctx, RedisCommandTimeout)
	defer cancel()

	// Enforce TTL via SET — never EXPIRE
	cmd := client.Set(cmdCtx, key, value, SessionTTL)
	if cmd.Err() != nil {
		c.circuit.recordFailure()
		return cmd.Err()
	}
	c.circuit.recordSuccess()
	return nil
}

// ClearShadowKeys is an emergency cleanup method — NOT for use by checkout flow
func (c *Client) ClearShadowKeys(ctx context.Context) (int64, error) {
	// Only allow if circuit is closed (safe state)
	if !c.circuit.IsAvailable() {
		return 0, ErrCircuitOpen
	}

	// Scan across all shards — use cluster client if available, or iterate manually
	var totalDeleted int64
	for _, client := range c.redisClients {
		// Use SCAN to avoid blocking Redis
		var cursor uint64
		for {
			keys, next, err := client.Scan(ctx, cursor, ShadowKeyPrefix+"*", 100).Result()
			if err != nil {
				return totalDeleted, err
			}

			if len(keys) > 0 {
				deleted, err := client.Del(ctx, keys...).Result()
				if err != nil {
					return totalDeleted, err
				}
				totalDeleted += deleted
			}

			if next == 0 {
				break
			}
			cursor = next
		}
	}
	return totalDeleted, nil
}
